Here are the MSTest comparison assertions for boundary checking and a complete test class for your `ScoreCalculator`:

**Key comparison assertions (MSTest 3.7+):**

```csharp
Assert.IsGreaterThan(lowerBound, actual);  // actual > lowerBound
Assert.IsLessThan(upperBound, actual);     // actual < upperBound
Assert.IsInRange(actual, low, high);       // low <= actual <= high
```

**Complete test class:**

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);

        Assert.IsGreaterThan(0.0, result);   // result > 0
        Assert.IsLessThan(100.0, result);    // result < 100
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_MidRange_IsInRange()
    {
        var result = _calculator.NormalizeScore(45, 100);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(45.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120, 100);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result); // never exceeds 100
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0, 50);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

